it("should return premium 55 G for 2 runes — 50 G base (2 x 25 G) + 5 G fee", () => {
  const input = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote" as const,
        items: [{ type: "rune" }, { type: "rune" }],
      },
    ],
  };
  const result = claimOffice(input);
  expect(result).toEqual({ results: [{ premium: 55 }] });
});

